# @cctt_verify {"v":2,"sym":"sympy.functions.elementary.tests.test_miscellaneous.test_root","kind":"function","src_hash":"dd61af0aa2da16ee","in":{"base":"Any"},"out":{"base":"Any","pred":"root(2, 2) == sqrt(2) and root(2, 1) == 2 and root(2, 3) == 2 ** Rational(1, 3) and root(2, 3) == cbrt(2) and root(2, -5) == 2 ** Rational(4, 5) / 2 and root(-2, 1) == -2 and root(-2, 2) == sqrt(2) * I and root(-2, 1) == -2 and root(x, 2) == sqrt(x) and root(x, 1) == x and root(x, 3) == x ** Rational(1, 3) and root(x, 3) == cbrt(x) and root(x, -5) == x ** Rational(-1, 5) and root(x, n) == x ** (1 / n) and root(x, -n) == x ** (-1 / n) and root(x, n, k) == (-1) ** (2 * k / n) * x ** (1 / n)"},"spec":{"lhs":"test_root()","rhs":"test_root produces the expected output","over":{"base":"Any"},"name":"test_root_correct"},"guarantee":"test_root produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.functions.elementary.tests.test_miscellaneous.test_root_correct","statement":"Path(test_root(x), test_root produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"6bb0fe97c743a816"}
def test_root():
    from sympy.abc import x
    n = Symbol('n', integer=True)
    k = Symbol('k', integer=True)

    assert root(2, 2) == sqrt(2)
    assert root(2, 1) == 2
    assert root(2, 3) == 2**Rational(1, 3)
    assert root(2, 3) == cbrt(2)
    assert root(2, -5) == 2**Rational(4, 5)/2

    assert root(-2, 1) == -2

    assert root(-2, 2) == sqrt(2)*I
    assert root(-2, 1) == -2

    assert root(x, 2) == sqrt(x)
    assert root(x, 1) == x
    assert root(x, 3) == x**Rational(1, 3)
    assert root(x, 3) == cbrt(x)
    assert root(x, -5) == x**Rational(-1, 5)

    assert root(x, n) == x**(1/n)
    assert root(x, -n) == x**(-1/n)

    assert root(x, n, k) == (-1)**(2*k/n)*x**(1/n)


