# @cctt_verify {"v":2,"sym":"sympy.functions.elementary.tests.test_miscellaneous.test_real_root","kind":"function","src_hash":"10638c07eb67882c","in":{"base":"Any"},"out":{"base":"Any","pred":"real_root(-8, 3) == -2 and real_root(-16, 4) == root(-16, 4) and real_root(r) == r and real_root(r1 + r2 + r3) == -1 + r2 + r3 and real_root(root(-2, 3)) == -root(2, 3) and real_root(-8.0, 3) == -2.0 and g.subs({'x': -8, 'n': 3}) == -2 and g.subs({'x': 8, 'n': 3}) == 2 and g.subs({'x': I, 'n': 3}) == cbrt(I) and g.subs({'x': -8, 'n': 2}) == sqrt(-8) and g.subs({'x': I, 'n': 2}) == sqrt(I)"},"spec":{"lhs":"test_real_root()","rhs":"test_real_root produces the expected output","over":{"base":"Any"},"name":"test_real_root_correct"},"guarantee":"test_real_root produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.functions.elementary.tests.test_miscellaneous.test_real_root_correct","statement":"Path(test_real_root(x), test_real_root produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"0aba9ecae35b2dd3"}
def test_real_root():
    assert real_root(-8, 3) == -2
    assert real_root(-16, 4) == root(-16, 4)
    r = root(-7, 4)
    assert real_root(r) == r
    r1 = root(-1, 3)
    r2 = r1**2
    r3 = root(-1, 4)
    assert real_root(r1 + r2 + r3) == -1 + r2 + r3
    assert real_root(root(-2, 3)) == -root(2, 3)
    assert real_root(-8., 3) == -2.0
    x = Symbol('x')
    n = Symbol('n')
    g = real_root(x, n)
    assert g.subs({"x": -8, "n": 3}) == -2
    assert g.subs({"x": 8, "n": 3}) == 2
    # give principle root if there is no real root -- if this is not desired
    # then maybe a Root class is needed to raise an error instead
    assert g.subs({"x": I, "n": 3}) == cbrt(I)
    assert g.subs({"x": -8, "n": 2}) == sqrt(-8)
    assert g.subs({"x": I, "n": 2}) == sqrt(I)


